-- =====================================================
-- 本番DB → Prod2 interop データ移行 SQL
-- Prod2(rlgaflpkkonsamsmxprt) の SQL Editor で実行
-- =====================================================

-- ① interop_topics テーブル作成（Prod2に未存在）
CREATE TABLE IF NOT EXISTS interop_topics (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  no INTEGER NOT NULL UNIQUE,
  major TEXT NOT NULL DEFAULT '',
  name TEXT NOT NULL,
  room_id TEXT NOT NULL DEFAULT '',
  topic1 TEXT NOT NULL DEFAULT '',
  topic2 TEXT NOT NULL DEFAULT '',
  topic3 TEXT NOT NULL DEFAULT '',
  axis_x REAL NOT NULL DEFAULT 0,
  axis_y REAL NOT NULL DEFAULT 0,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active BOOLEAN NOT NULL DEFAULT true,
  url TEXT NOT NULL DEFAULT '',
  point_links JSONB NOT NULL DEFAULT '[]'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ① 既存データをクリア（Prod2のUUIDと本番DBのUUIDが異なるためFK違反回避）
DELETE FROM interop_posts;
DELETE FROM interop_board_topics;
DELETE FROM interop_sub_categories;
DELETE FROM interop_categories;

-- ② interop_categories
ON CONFLICT DO NOTHING;

-- ③ interop_sub_categories
ON CONFLICT DO NOTHING;

-- ④ interop_board_topics
ON CONFLICT DO NOTHING;

-- ⑤ interop_settings
ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;

-- ⑥ interop_axis_config
ON CONFLICT (id) DO UPDATE SET x_left=EXCLUDED.x_left, x_right=EXCLUDED.x_right, y_top=EXCLUDED.y_top, y_bottom=EXCLUDED.y_bottom, updated_at=EXCLUDED.updated_at;

-- ⑦ interop_topics (28件)
ON CONFLICT DO NOTHING;

-- ⑧ interop_topic_position (28件)
ON CONFLICT (topic_no) DO UPDATE SET x=EXCLUDED.x, y=EXCLUDED.y, updated_at=EXCLUDED.updated_at;

-- ⑨ interop_posts (112件)
ON CONFLICT DO NOTHING;
ALTER TABLE interop_posts ADD COLUMN IF NOT EXISTS parent_post_id UUID REFERENCES interop_posts(id) ON UPDATE CASCADE ON DELETE CASCADE;
